package com.hospital.management.controller.admin;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.DepartmentServiceImpl;import com.hospital.management.util.RequestUtil;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;
@WebServlet("/admin/departments/create")public class DepartmentCreateServlet extends HttpServlet{private final DepartmentService service;public DepartmentCreateServlet(){this(new DepartmentServiceImpl());}public DepartmentCreateServlet(DepartmentService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{q.setAttribute("formMode","CREATE");q.setAttribute("department",new Department(null,"","","","ACTIVE"));forward(q,r);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{q.setCharacterEncoding("UTF-8");Department d=Form.department(q,null);ServiceResult<Long>x=service.createDepartment(d,RequestUtil.buildAuditContext(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/admin/departments?message=created");return;}q.setAttribute("formMode","CREATE");q.setAttribute("department",d);q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());forward(q,r);}private void forward(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{q.getRequestDispatcher("/WEB-INF/views/admin/departments/form.jsp").forward(q,r);}}
